// === MODE OFF-GRID : Gestion avec protection anti-oscillation ===

// PARAMÈTRES CRITIQUES
const FREQ_HIGH = 52.0;       // Seuil haut pour couper (Hz)
const FREQ_LOW = 50.3;        // Seuil bas pour rallumer (Hz) - LARGE HYSTÉRÉSIS
const DELAY_OFF = 15;         // Délai avant coupure (secondes)
const DELAY_ON = 45;          // Délai avant rallumage (secondes)
const MIN_OFF_DURATION = 120; // Minimum 2 minutes OFF (secondes)

// État actuel
let currentState = context.get('shelly_state') || 'ON';
let timerHigh = context.get('timer_high') || null;
let timerLow = context.get('timer_low') || null;
let lastOffTime = context.get('last_off_time') || null;

// === PROTECTION : Vérifier durée minimum OFF ===
if (currentState === 'OFF' && lastOffTime !== null) {
    const timeSinceOff = (Date.now() - lastOffTime) / 1000;
    const remainingTime = MIN_OFF_DURATION - timeSinceOff;

    if (remainingTime > 0) {
        // Encore dans la période minimum OFF → Bloquer tout rallumage
        context.set('timer_low', null); // Reset timer rallumage
        node.status({
            fill:"red",
            shape:"ring",
            text:`🔴 OFF verrouillé ${remainingTime.toFixed(0)}s (${freq}Hz)`
        });
        return null;
    }
}

// === Machine à états avec hystérésis ===

if (freq >= FREQ_HIGH) {
    // Fréquence haute détectée → Demande de coupure
    if (!timerHigh) {
        timerHigh = Date.now();
        context.set('timer_high', timerHigh);
    }

    const elapsedHigh = (Date.now() - timerHigh) / 1000;

    if (elapsedHigh >= DELAY_OFF && currentState === 'ON') {
        // Condition remplie → Couper DEYE
        currentState = 'OFF';
        const now = Date.now();
        context.set('shelly_state', 'OFF');
        context.set('last_off_time', now); // Enregistrer l'heure de coupure
        context.set('timer_low', null);

        msg.payload = { 
            action: 'OFF', 
            freq: freq, 
            reason: `OFF-GRID: Freq ${freq}Hz > ${FREQ_HIGH}Hz pendant ${DELAY_OFF}s` 
        };
        node.status({fill:"red",shape:"dot",text:`🔴 OFF (${freq}Hz)`});
        return msg;

    } else if (currentState === 'OFF') {
        const timeSinceOff = lastOffTime ? (Date.now() - lastOffTime) / 1000 : 0;
        node.status({
            fill:"red",
            shape:"ring",
            text:`OFF maintenu ${timeSinceOff.toFixed(0)}s (${freq}Hz)`
        });
    } else {
        node.status({
            fill:"yellow",
            shape:"ring",
            text:`${freq}Hz - Attente ${elapsedHigh.toFixed(0)}/${DELAY_OFF}s`
        });
    }

    context.set('timer_low', null);

} else if (freq <= FREQ_LOW) {
    // Fréquence basse détectée → Demande de rallumage

    // Vérifier si on peut rallumer (durée minimum OFF écoulée)
    if (currentState === 'OFF' && lastOffTime !== null) {
        const timeSinceOff = (Date.now() - lastOffTime) / 1000;
        if (timeSinceOff < MIN_OFF_DURATION) {
            // Pas encore 2 minutes OFF → Bloquer
            node.status({
                fill:"red",
                shape:"ring",
                text:`🔒 OFF verrouillé ${(MIN_OFF_DURATION - timeSinceOff).toFixed(0)}s`
            });
            return null;
        }
    }

    // Durée minimum OK → Démarrer timer rallumage
    if (!timerLow) {
        timerLow = Date.now();
        context.set('timer_low', timerLow);
    }

    const elapsedLow = (Date.now() - timerLow) / 1000;

    if (elapsedLow >= DELAY_ON && currentState === 'OFF') {
        // Condition remplie → Rallumer DEYE
        currentState = 'ON';
        context.set('shelly_state', 'ON');
        context.set('last_off_time', null); // Reset compteur OFF
        context.set('timer_high', null);

        msg.payload = { 
            action: 'ON', 
            freq: freq, 
            reason: `OFF-GRID: Freq ${freq}Hz < ${FREQ_LOW}Hz pendant ${DELAY_ON}s (après 2min OFF)` 
        };
        node.status({fill:"green",shape:"dot",text:`🟢 ON (${freq}Hz)`});
        return msg;

    } else if (currentState === 'ON') {
        node.status({fill:"green",shape:"ring",text:`ON stable (${freq}Hz)`});
    } else {
        node.status({
            fill:"yellow",
            shape:"ring",
            text:`${freq}Hz - Attente ${elapsedLow.toFixed(0)}/${DELAY_ON}s`
        });
    }

    context.set('timer_high', null);

} else {
    // Zone d'hystérésis (entre FREQ_LOW et FREQ_HIGH)
    context.set('timer_high', null);
    context.set('timer_low', null);

    if (currentState === 'ON') {
        node.status({fill:"green",shape:"ring",text:`ON stable (${freq}Hz)`});
    } else {
        const timeSinceOff = lastOffTime ? (Date.now() - lastOffTime) / 1000 : 0;
        node.status({
            fill:"red",
            shape:"ring",
            text:`OFF stable ${timeSinceOff.toFixed(0)}s (${freq}Hz)`
        });
    }
}

return null;

