const PRODUCTION_MIN    = 2000;  // W
const DEBOUNCE_MINUTES  = 5;     // délai de confirmation pour conditions instables

const acIgnored  = flow.get('wh_ac_ignored');
const soc        = flow.get('wh_soc');
const current    = flow.get('wh_battery_current');
const production = flow.get('wh_production') || 0;
const now        = Date.now();

// --- Conditions immédiates (stables) ---
const acConnected = (acIgnored !== null && acIgnored !== undefined && acIgnored === 0);
const socLow      = (soc !== null && soc !== undefined && soc < 95);

// --- Conditions avec debounce (instables) ---
// discharging
const dischargingNow = (current !== null && current !== undefined && current <= 0);
if (dischargingNow) {
    if (!context.get('dischargeStart')) {
        context.set('dischargeStart', now);
    }
} else {
    context.set('dischargeStart', null);
}
const dischargeStart    = context.get('dischargeStart');
const dischargeElapsed  = dischargeStart ? (now - dischargeStart) / 60000 : 0;
const discharging       = dischargingNow && (dischargeElapsed >= DEBOUNCE_MINUTES);

// prodInsuff
const prodInsuffNow = (production <= PRODUCTION_MIN);
if (prodInsuffNow) {
    if (!context.get('prodInsuffStart')) {
        context.set('prodInsuffStart', now);
    }
} else {
    context.set('prodInsuffStart', null);
}
const prodInsuffStart   = context.get('prodInsuffStart');
const prodInsuffElapsed = prodInsuffStart ? (now - prodInsuffStart) / 60000 : 0;
const prodInsuff        = prodInsuffNow && (prodInsuffElapsed >= DEBOUNCE_MINUTES);

// --- Décision ---
const vacation = acConnected || socLow || discharging || prodInsuff;

let reasons = [];
if (acConnected) reasons.push('AC connecté');
if (socLow)      reasons.push(`SOC ${soc}%<85%`);
if (discharging) reasons.push(`Décharge ${current}A (${dischargeElapsed.toFixed(1)}min)`);
if (prodInsuff)  reasons.push(`Prod ${production}W≤${PRODUCTION_MIN}W (${prodInsuffElapsed.toFixed(1)}min)`);

// Statut détaillé même quand en attente de confirmation
let pending = [];
if (dischargingNow && !discharging) pending.push(`Décharge ${dischargeElapsed.toFixed(1)}/${DEBOUNCE_MINUTES}min`);
if (prodInsuffNow  && !prodInsuff)  pending.push(`Prod ${prodInsuffElapsed.toFixed(1)}/${DEBOUNCE_MINUTES}min`);

msg.payload = {
    mode: vacation ? 'vacation' : 'heat_pump',
    ac_ignored: acIgnored,
    soc: soc,
    battery_current: current,
    production: production,
    reasons: vacation ? reasons : [`SOC≥85%, AC ignoré, Charge, Prod ${production}W>${PRODUCTION_MIN}W`]
};

if (vacation) {
    node.status({fill:'yellow', shape:'ring', text:`VACATION: ${reasons.join(' | ')}`});
    return [null, msg];
} else if (pending.length > 0) {
    node.status({fill:'orange', shape:'ring', text:`⏳ Attente: ${pending.join(' | ')}`});
    return [null, null];
} else {
    node.status({fill:'cyan', shape:'dot', text:`HEAT_PUMP: Prod ${production}W, SOC ${soc}%`});
    return [msg, null];
}

