return msg;

if (msg.statusCode !== 200) {
    node.error('Erreur API LG ThinQ: ' + msg.statusCode + ' ' + JSON.stringify(msg.payload));
    return null;
}

const r = msg.payload.response;
if (!r || !r.waterHeaterJobMode || !r.temperature) {
    node.error('Réponse API inattendue: ' + JSON.stringify(msg.payload));
    return null;
}

const mode        = r.waterHeaterJobMode.currentJobMode;    // 'HEAT_PUMP' | 'TURBO' | 'VACATION'
const operation   = r.operation ? r.operation.waterHeaterOperationMode : 'POWER_ON';
const currentTemp = r.temperature.currentTemperature;
const targetTemp  = r.temperature.targetTemperature;

// State mapping → /State D-Bus Venus OS (com.victronenergy.heatpump)
// 0 = Off / Vacation
// 1 = Heat Pump (pompe à chaleur mode normal)
// 2 = Turbo / Boost
const stateMapping = {
    'HEAT_PUMP': 1,
    'TURBO':     2,
    'VACATION':  0
};
const isPoweredOn = operation === 'POWER_ON';
const state = isPoweredOn ? (stateMapping[mode] ?? 1) : 0;

// Payload Venus OS D-Bus heatpump
const payload = {
    State:             state,
    Temperature:       currentTemp,
    TargetTemperature: targetTemp,
    Position:          0          // 0 = AC Output
};

// Stocker dans le contexte global pour le keepalive
global.set('heatpump_payload', payload);

// Afficher le statut du nœud
const modeLabel = isPoweredOn ? mode : 'OFF';
node.status({
    fill:  mode === 'TURBO' ? 'red' : mode === 'HEAT_PUMP' ? 'green' : 'yellow',
    shape: 'dot',
    text:  `${modeLabel} | ${currentTemp}°C → ${targetTemp}°C`
});

// Output 1 : payload MQTT pour Venus OS
// Output 2 : debug complet
const out1 = { topic: 'santuario/heatpump/1/venus', payload: JSON.stringify(payload) };
const out2 = { payload: { mode, operation, state, currentTemp, targetTemp, rawResponse: r } };

return [out1, out2];

const payload = global.get('heatpump_payload');
if (!payload) {
    node.status({ fill: 'grey', shape: 'ring', text: 'en attente du 1er fetch' });
    return null;
}
node.status({
    fill:  'blue',
    shape: 'ring',
    text:  `keepalive | ${payload.Temperature}°C → ${payload.TargetTemperature}°C`
});
return {
    topic:   'santuario/heatpump/1/venus',
    payload: JSON.stringify(payload)
};

