node.status({fill:'blue', text:`P: ${v}W`});
return msg;

const soc      = flow.get('soc_percent') || 0;
const voltage  = flow.get('voltage_v')   || 0;
const current  = flow.get('current_a')   || 0;
const power    = flow.get('power_w')     || 0;

node.status({fill:'green', shape:'dot', text:`${soc}% | ${voltage}V | ${current}A | ${power}W`});

const msg_out = {
    topic: 'santuario/system/venus',
    payload: JSON.stringify({
        Soc: soc,
        Voltage: voltage,
        Current: current,
        Power: power
    }),
    retain: true
};

return msg_out;

const etat = msg.payload;
const on = (etat === 'ON');
flow.set('tongou_sy2_state', on);
node.status({fill: on ? 'green' : 'grey', shape: 'dot', text: etat});
msg.payload = on;
return msg;

const d = msg.payload;
if (d && d.ENERGY) {
    const e = d.ENERGY;
    flow.set('tongou_sy2_power_w',   e.Power   || 0);
    flow.set('tongou_sy2_voltage_v', e.Voltage || 0);
    flow.set('tongou_sy2_current_a', e.Current || 0);
    flow.set('tongou_sy2_today_kwh', e.Today   || 0);
    flow.set('tongou_sy2_total_kwh', e.Total   || 0);
    node.status({fill:'blue', shape:'dot',
        text: `${e.Power}W  ${e.Voltage}V  ${e.Current}A`});
}
return msg;
